-- Session 3.4 — Canonical library layer for stages and works.
--
-- Mirrors the pattern established by system_resource_articles (Session 3.0):
-- centrally curated, read-only for authenticated users, writes via service_role.
-- These tables sit alongside system_resource_articles and complete the
-- "library layer" of the two-layer architecture (see
-- rovno-canonical-architecture-design.md §3, §4.1, §4.2).
--
-- Stages and works are NOT seeded here. A follow-up migration after Round 5
-- of seed-fill polish populates them with the ~30 canonical stages and ~692
-- canonical works from rovno-seed-fill-working.md.
--
-- Construct families used here (create table / partial create index /
-- set_updated_at trigger / grant select / enable RLS / select policy) all
-- appear verbatim in 20260511120000_system_resource_articles_and_unit_conversions.sql,
-- which is a curated-mirror source file. This migration is therefore safe to
-- include in DEFAULT_SOURCE_FILES so the two library tables surface on the
-- Templates contract slice.

create table public.system_stage_articles (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  description text not null default '',
  default_sort_hint integer not null default 100,
  category_tag text not null default 'general',
  source text not null default 'rovno_seed',
  source_version text,
  archived boolean not null default false,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint system_stage_articles_name_nonempty
    check (length(trim(name)) > 0)
);

-- Unique by display name only among the active (non-archived) rows, so an
-- archived duplicate name does not block re-curation under the same name.
create unique index idx_system_stage_articles_name_unique_active
  on public.system_stage_articles(name)
  where archived = false;

create index idx_system_stage_articles_sort
  on public.system_stage_articles(default_sort_hint);

create index idx_system_stage_articles_archived
  on public.system_stage_articles(archived)
  where archived = false;

create trigger set_system_stage_articles_updated_at
before update on public.system_stage_articles
for each row execute function public.set_updated_at();

-- Note: system_work_articles.default_resource_type is intentionally restricted
-- to a 3-value subset ('labor','subcontractor','other') of the canonical
-- resource_type vocabulary ('material','tool','labor','subcontractor',
-- 'overhead','other'). A work article models an activity, so its suggested
-- default resource line is labor or subcontract; materials/tools/overhead
-- attach as their own resource lines, not as the work's own type. This is why
-- this column diverges from the identically-named, material-centric column on
-- system_resource_articles. The value is a seed-time UI default only and is
-- never propagated by apply_template_stage_to_estimate.
create table public.system_work_articles (
  id uuid primary key default gen_random_uuid(),
  parent_stage_article_id uuid not null
    references public.system_stage_articles(id) on delete restrict,
  name text not null,
  description text not null default '',
  default_unit text not null,
  default_qty numeric(14,3) not null default 1
    check (default_qty >= 0),
  default_sort_hint integer not null default 100,
  default_resource_type text not null default 'labor'
    check (default_resource_type in ('labor','subcontractor','other')),
  source text not null default 'rovno_seed',
  source_version text,
  archived boolean not null default false,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint system_work_articles_name_nonempty
    check (length(trim(name)) > 0),
  constraint system_work_articles_default_unit_nonempty
    check (length(trim(default_unit)) > 0)
);

create index idx_system_work_articles_stage
  on public.system_work_articles(parent_stage_article_id);

create index idx_system_work_articles_stage_sort
  on public.system_work_articles(parent_stage_article_id, default_sort_hint);

create index idx_system_work_articles_archived
  on public.system_work_articles(archived)
  where archived = false;

create trigger set_system_work_articles_updated_at
before update on public.system_work_articles
for each row execute function public.set_updated_at();

-- Grants and RLS. Library articles are a global registry: any authenticated
-- user may read; writes happen only via service_role (CI migrations or
-- scheduled imports), so no INSERT/UPDATE/DELETE policies are defined.
grant select on table
  public.system_stage_articles,
  public.system_work_articles
to authenticated;

alter table public.system_stage_articles enable row level security;
alter table public.system_work_articles enable row level security;

create policy system_stage_articles_select on public.system_stage_articles
for select
to authenticated
using (true);

create policy system_work_articles_select on public.system_work_articles
for select
to authenticated
using (true);
